// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
  return date.toLocaleDateString(locale, { 
    year: 'numeric', 
    month: '2-digit', 
    day: '2-digit' 
  });
}

function formaterDateHeure(dateStr, langue) {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
  return date.toLocaleString(locale, { 
    year: 'numeric', 
    month: '2-digit', 
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function getEmoji(jours) {
  if (jours <= 2) return '🔴';
  if (jours === 3) return '🟠';
  if (jours === 4) return '🟡';
  return '🟢';
}

// ─────────────────────────────────────────────────────────────
// FONCTION DE GÉNÉRATION DE MESSAGE PRINCIPAL
// ─────────────────────────────────────────────────────────────

function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;

  const destinataire = data.destinataire_principal;
  const stats = data.statistiques;
  const attestations = data.attestations;

  // ─── EMAIL ───
  let emailSubject = T.sujet_email[data.type_destinataire] || T.sujet_email.SALARIE;
  emailSubject += ` - ${stats.total_attestations} attestation(s)`;

  let emailBody = `${T.salutation} ${destinataire.prenom} ${destinataire.nom},\n\n`;
  emailBody += `${T.introduction[data.type_destinataire]}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_attestations}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;
  emailBody += `${T.delai_total}: ${stats.delai_total} ${T.jours}\n`;

  if (data.type_destinataire !== 'SALARIE') {
    emailBody += `\n${T.salarie_concerne}: ${data.salarie.prenom} ${data.salarie.nom} (${data.salarie.code})\n`;
  }

  emailBody += `\n═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_attestations}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  attestations.forEach((att, index) => {
    emailBody += `${index + 1}. ${getEmoji(att.jours_restants)} ${att.numero_attestation}\n`;
    emailBody += `   📅 ${T.date_creation}: ${formaterDateHeure(att.date_creation_attestation, langue)}\n`;
    emailBody += `   🧑 ${T.salarie_concerne}: ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom} (${att.salarie_concerne.code})\n`;
    emailBody += `   ⏰ ${T.delai}: ${att.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(att.date_limite, langue)})\n`;
    if (att.jours_restants <= 2) {
      emailBody += `   🚨 ${T.urgent}\n`;
    }
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    emailBody += `🚨 ${T.action_requise}: ${T.urgent}\n`;
  } else {
    emailBody += `📌 ${T.instruction}\n`;
  }
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  emailBody += `📞 ${T.contact}:\n`;
  if (data.superieur && data.superieur.email) {
    emailBody += `   ${T.superieur || 'Supérieur'}: ${data.superieur.prenom} ${data.superieur.nom}\n`;
    emailBody += `   Email: ${data.superieur.email}\n`;
    emailBody += `   Tel: ${data.superieur.telephone || 'N/A'}\n`;
  }
  if (data.salarie && data.salarie.email) {
    emailBody += `   ${T.salarie_concerne}: ${data.salarie.prenom} ${data.salarie.nom}\n`;
    emailBody += `   Email: ${data.salarie.email}\n`;
    emailBody += `   Tel: ${data.salarie.telephone || 'N/A'}\n`;
  }
  emailBody += `\n`;

  emailBody += `${T.cordialement},\n\n`;
  emailBody += `${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  if (data.type_destinataire === 'PDG') {
    emailBody += `🔴 Notification URGENTE envoyée au PDG\n`;
  }
  emailBody += `${T.ne_pas_repondre}\n`;

  // ─── TELEGRAM ───
  let telegramMessage = `${getEmoji(stats.jours_min)} *${T.sujet_email[data.type_destinataire]}*\n`;
  telegramMessage += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `👤 *${destinataire.prenom} ${destinataire.nom}*\n\n`;
  telegramMessage += `📊 *${T.section_stats}*\n`;
  telegramMessage += `${T.total}: *${stats.total_attestations}*\n`;
  telegramMessage += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;

  telegramMessage += `📋 *${T.section_attestations}*\n\n`;

  attestations.slice(0, 5).forEach((att, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(att.jours_restants)} *${att.numero_attestation}*\n`;
    telegramMessage += `   📅 ${formaterDate(att.date_creation_attestation, langue)}\n`;
    telegramMessage += `   🧑 ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom}\n`;
    telegramMessage += `   ⏰ ${att.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });


  if (attestations.length > 5) {
    telegramMessage += `... et ${attestations.length - 5} autre(s) attestation(s)\n\n`;
  }

  if (stats.jours_min <= 2) {
    telegramMessage += `🚨 *${T.urgent}*\n\n`;
  }

  return {
    email: {
      subject: emailSubject,
      body: emailBody
    },
    telegram: {
      text: telegramMessage,
      parse_mode: 'Markdown'
    }
  };
}

// ─────────────────────────────────────────────────────────────
// FONCTION DE GÉNÉRATION DE MESSAGE CC
// ─────────────────────────────────────────────────────────────

function genererMessageCC(data, destinataireCC, typeDestinatairePrincipal) {
  const langue = destinataireCC.langue || data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;

  const stats = data.statistiques;
  const attestations = data.attestations;
  const destinatairePrincipal = data.destinataire_principal;

  // Déterminer l'intro selon le contexte
  let message_envoye_a = '';
  let message_envoye_a_email = '';

  if (typeDestinatairePrincipal === 'SUPERIEUR') {
    // CC au salarié depuis supérieur
    message_envoye_a = `${T.cc_message.votre_superieur} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
    message_envoye_a_email = `${T.cc_message.votre_superieur} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
  } else if (typeDestinatairePrincipal === 'PDG') {
    // CC depuis PDG
    if (destinataireCC.code === data.superieur?.code) {
      // Message pour le supérieur
      message_envoye_a = `${T.cc_message.le_pdg} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
      message_envoye_a_email = `${T.cc_message.le_pdg} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
    } else {
      // Message pour le salarié
      message_envoye_a = `${T.cc_message.le_pdg} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
      message_envoye_a_email = `${T.cc_message.le_pdg} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
    }
  }

  // ─── MESSAGE EMAIL CC ───
  let emailSubject = `${T.copie_info} - ${T.sujet_email[typeDestinatairePrincipal]} - ${stats.total_attestations} attestation(s)`;

  let emailBody = `${T.salutation} ${destinataireCC.prenom} ${destinataireCC.nom},\n\n`;
  emailBody += `${T.cc_message.base} ${message_envoye_a_email}.\n\n`;

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_attestations}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;
  emailBody += `${T.delai_total}: ${stats.delai_total} ${T.jours}\n\n`;

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_attestations}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  attestations.forEach((att, index) => {
    emailBody += `${index + 1}. ${getEmoji(att.jours_restants)} ${att.numero_attestation}\n`;
    emailBody += `   📅 ${T.date_creation}: ${formaterDateHeure(att.date_creation_attestation, langue)}\n`;

    emailBody += `   🧑 ${T.salarie_concerne}: ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom} (${att.salarie_concerne.code})\n`;
    emailBody += `   ⏰ ${T.delai}: ${att.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(att.date_limite, langue)})\n`;
    if (att.jours_restants <= 2) {
      emailBody += `   🚨 ${T.urgent}\n`;
    }
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `${T.cc_message.action}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  emailBody += `📞 ${T.contact}:\n`;
  if (data.superieur && data.superieur.email) {
    emailBody += `   Email: ${data.superieur.email}\n`;
    emailBody += `   Tel: ${data.superieur.telephone || 'N/A'}\n`;
  }
  emailBody += `\n`;

  emailBody += `${T.cordialement},\n\n`;
  emailBody += `${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  emailBody += `📋 ${T.copie_info}\n`;
  emailBody += `${T.ne_pas_repondre}\n`;

  // ─── MESSAGE TELEGRAM CC ───
  let telegramMessage = `${T.copie_info}\n`;
  telegramMessage += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `${T.salutation} *${destinataireCC.prenom} ${destinataireCC.nom}*,\n\n`;
  telegramMessage += `${T.cc_message.base} ${message_envoye_a}.\n\n`;

  telegramMessage += `📊 *${T.section_stats}*\n`;
  telegramMessage += `${T.total}: *${stats.total_attestations}*\n`;
  telegramMessage += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;

  telegramMessage += `📋 *${T.section_attestations}*\n\n`;
  attestations.slice(0, 3).forEach((att, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(att.jours_restants)} *${att.numero_attestation}*\n`;
    telegramMessage += `   📅 ${formaterDate(att.date_creation_attestation, langue)}\n`;
    telegramMessage += `   🧑 ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom}\n`;
    telegramMessage += `   ⏰ ${att.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });

  if (attestations.length > 3) {
    telegramMessage += `... et ${attestations.length - 3} autre(s) attestation(s)\n\n`;
  }

  telegramMessage += `${T.cc_message.action}\n\n`;

  return {
    email: {
      subject: emailSubject,
      body: emailBody
    },
    telegram: {
      text: telegramMessage,
      parse_mode: 'Markdown'
    }
  };
}

