const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messagesPrincipal = genererMessagePrincipal(data);

  // ✅ Détermine les flags pour les CC
  const envoyer_cc_salarie = (data.type_destinataire === 'SUPERIEUR' || data.type_destinataire === 'PDG');
  const envoyer_cc_superieur = (data.type_destinataire === 'PDG');

  // ═══════════════════════════════════════════════════════════
  // 1. MESSAGE PRINCIPAL
  // ═══════════════════════════════════════════════════════════
  results.push({
    json: {
      ...data,
      messages: messagesPrincipal,
      type_envoi: 'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      envoyer_cc_salarie: envoyer_cc_salarie,
      envoyer_cc_superieur: envoyer_cc_superieur,
      meta: {
        ...data.meta,
        langue_utilisee: data.meta.langue_message || 'FRA',
        date_generation: new Date().toISOString()
      }
    }
  });

  // ═══════════════════════════════════════════════════════════
  // 2. MESSAGES CC DYNAMIQUES
  // ═══════════════════════════════════════════════════════════

  if (data.type_destinataire === 'SUPERIEUR') {
    // 🔸 SUPERIEUR notifié → CC au SALARIE
    if (data.salarie && data.salarie.chat_id) {
      const messagesCC = genererMessageCC(data, data.salarie, 'SUPERIEUR');

      results.push({
        json: {
          ...data,
          messages: messagesCC,
          type_envoi: 'CC',
          destinataire_final: data.salarie,
          cc_pour_profil: 'SALARIE',
          envoyer_cc_salarie: true,
          envoyer_cc_superieur: false,
          meta: {
            ...data.meta,
            langue_utilisee: data.salarie.langue || data.meta.langue_message || 'FRA',
            date_generation: new Date().toISOString()
          }
        }
      });
    }
  } 
  else if (data.type_destinataire === 'PDG') {
    // 🔸 PDG notifié → CC au SUPERIEUR + CC au SALARIE

    // CC au SUPERIEUR
    if (data.superieur && data.superieur.chat_id) {
      const messagesCCSuperieur = genererMessageCC(data, data.superieur, 'PDG');

      results.push({
        json: {
          ...data,
          messages: messagesCCSuperieur,
          type_envoi: 'CC',
          destinataire_final: data.superieur,
          cc_pour_profil: 'SUPERIEUR',
          envoyer_cc_salarie: false,
          envoyer_cc_superieur: true,
          meta: {
            ...data.meta,
            langue_utilisee: data.superieur.langue || data.meta.langue_message || 'FRA',
            date_generation: new Date().toISOString()
          }
        }
      });
    }

    // CC au SALARIE
    if (data.salarie && data.salarie.chat_id) {
      const messagesCCSalarie = genererMessageCC(data, data.salarie, 'PDG');

      results.push({
        json: {
          ...data,
          messages: messagesCCSalarie,
          type_envoi: 'CC',
          destinataire_final: data.salarie,
          cc_pour_profil: 'SALARIE',
          envoyer_cc_salarie: true,
          envoyer_cc_superieur: false,
          meta: {
            ...data.meta,
            langue_utilisee: data.salarie.langue || data.meta.langue_message || 'FRA',
            date_generation: new Date().toISOString()
          }
        }
      });
    }
  }
});

